import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"Установка Fabric в Windows","description":"Пошаговое руководство по установке Fabric в Windows.","frontmatter":{"title":"Установка Fabric в Windows","description":"Пошаговое руководство по установке Fabric в Windows.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ru_ru/players/installing-fabric/windows.md","filePath":"translated/ru_ru/players/installing-fabric/windows.md","lastUpdated":1770561656000}`);var s={name:`ru_ru/players/installing-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка Fabric в Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка Fabric в Windows”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Загрузите программу установки Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Загрузите программу установки Fabric”">​</a></h2><p>Загрузите версию Fabric Installer с расширением <code>.exe</code> с <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">веб-сайта Fabric</a>, нажав на кнопку <code>Download for Windows</code> (Загрузить для Windows).</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Версия <code>.exe</code> для Windows не требует установки Java, поскольку использует Java, входящую в состав официального Minecraft Launcher.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запустите программу установки Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запустите программу установки Fabric”">​</a></h2><p>Перед запуском установщика закройте Minecraft и Minecraft Launcher.</p><p>После запуска установщика вы должны увидеть экран, похожий на этот:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установщик Fabric с подсвеченным «Установить»" loading="lazy"></p><p>Выберите желаемую версию Minecraft и нажмите «Установить». Убедитесь, что опция «Создать профиль» отмечена.</p><h2 id="3-finish-setup" tabindex="-1">3. Завершение настроек <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Завершение настроек”">​</a></h2><p>После завершения установки откройте Minecraft Launcher. Затем выберите профиль Fabric в раскрывающемся списке версий и нажмите «Играть».</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher с выбранным профилем Fabric" loading="lazy"></p><p>Теперь вы можете добавлять моды в свою игру. См. руководство <a href="./../finding-mods">Поиск надежных модов</a> для получения доп. информации.</p><p>Если у вас возникнут проблемы, не стесняйтесь обращаться за помощью в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> в канале <code>#player-support</code>.</p>`,14)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};